messages.content:
This is a missed-optimization in InstCombine.

The following program reveals the missed optimization.
The source program is
```llvm
define <8 x i1> @fcmp_one_sel_x_negx_vec(<8 x float> %x) {
  %f = fcmp one <8 x float> %x, zeroinitializer
  %neg = fneg <8 x float> %x
  %sel = select <8 x i1> %f, <8 x float> %x, <8 x float> %neg
  %res = fcmp one <8 x float> %sel, zeroinitializer
  ret <8 x i1> %res
}

```

However, current LLVM cannot optimize the source program. The expected optimized program is
```llvm
define <8 x i1> @fcmp_one_sel_x_negx_vec(<8 x float> %x) {
  %res = fcmp one <8 x float> %x, zeroinitializer
  ret <8 x i1> %res
}

```
Please modify the following code in llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp:InstCombinerImpl::visitFCmpInst to implement the missed optimization:
```cpp
    if (IntPred != ICmpInst::BAD_ICMP_PREDICATE) {
      Type *IntTy = X->getType();
      const APInt &SignMask = ~APInt::getSignMask(IntTy->getScalarSizeInBits());
      Value *MaskX = Builder.CreateAnd(X, ConstantInt::get(IntTy, SignMask));
      return new ICmpInst(IntPred, MaskX, ConstantInt::getNullValue(IntTy));
    }
  }

  // Handle fcmp with instruction LHS and constant RHS.
  Instruction *LHSI;
  Constant *RHSC;
  if (match(Op0, m_Instruction(LHSI)) && match(Op1, m_Constant(RHSC))) {
    switch (LHSI->getOpcode()) {
    case Instruction::PHI:
      if (Instruction *NV = foldOpIntoPhi(I, cast<PHINode>(LHSI)))
        return NV;
      break;
    case Instruction::SIToFP:
    case Instruction::UIToFP:
      if (Instruction *NV = foldFCmpIntToFPConst(I, LHSI, RHSC))
        return NV;
      break;
    case Instruction::FDiv:
      if (Instruction *NV = foldFCmpReciprocalAndZero(I, LHSI, RHSC))
        return NV;
      break;
